+    let mut elevated_dims = BTreeMap::new();
+    elevated_dims.insert("exploration_rate".into(), 150_000);
+    elevated_dims.insert("sandbox_strictness".into(), 850_000);
+    elevated_dims.insert("gc_aggressiveness".into(), 550_000);
