+            description: "All sites abstain when budget exceeded".into(),
+            family: EscapeCertSpecimenFamily::BudgetExhaustion,
+            expected_outcome: EscapeCertExpectedOutcome::BudgetExceeded,
+        },
+        // ── Eligibility Envelope ──
