+            description: "Envelope counts match certificate details".into(),
+            family: EscapeCertSpecimenFamily::EligibilityEnvelope,
+            expected_outcome: EscapeCertExpectedOutcome::EnvelopeComputed,
+        },
+        EscapeCertSpecimen {
